// Mock product data for the demo product detail page.
// Images are inline SVG data URIs so the page is fully offline + deterministic.

function swatchImage(bg: string, accent: string, label: string): string {
  const svg = `<svg xmlns='http://www.w3.org/2000/svg' width='800' height='800' viewBox='0 0 800 800'>
    <defs><linearGradient id='g' x1='0' y1='0' x2='1' y2='1'>
      <stop offset='0' stop-color='${bg}'/><stop offset='1' stop-color='${accent}'/>
    </linearGradient></defs>
    <rect width='800' height='800' fill='url(#g)'/>
    <g fill='none' stroke='rgba(255,255,255,0.85)' stroke-width='14' stroke-linecap='round'>
      <circle cx='400' cy='330' r='150'/>
      <path d='M250 330 V250 a150 150 0 0 1 300 0 V330'/>
      <rect x='210' y='330' width='80' height='150' rx='30' fill='rgba(255,255,255,0.85)' stroke='none'/>
      <rect x='510' y='330' width='80' height='150' rx='30' fill='rgba(255,255,255,0.85)' stroke='none'/>
    </g>
    <text x='400' y='620' font-family='system-ui, sans-serif' font-size='40' font-weight='700'
      fill='rgba(255,255,255,0.9)' text-anchor='middle'>${label}</text>
  </svg>`;
  return `data:image/svg+xml;utf8,${encodeURIComponent(svg)}`;
}

function relatedImage(bg: string, label: string): string {
  const svg = `<svg xmlns='http://www.w3.org/2000/svg' width='600' height='600' viewBox='0 0 600 600'>
    <rect width='600' height='600' fill='${bg}'/>
    <circle cx='300' cy='260' r='120' fill='rgba(255,255,255,0.18)'/>
    <text x='300' y='470' font-family='system-ui, sans-serif' font-size='34' font-weight='700'
      fill='rgba(255,255,255,0.9)' text-anchor='middle'>${label}</text>
  </svg>`;
  return `data:image/svg+xml;utf8,${encodeURIComponent(svg)}`;
}

