"use client";

import * as React from "react";
import {
  Breadcrumb,
  Badge,
  Button,
  Card,
  CardContent,
  CardHeader,
  CardTitle,
  CardDescription,
  Icon,
  Img,
  Separator,
  Tabs,
  TabsList,
  TabsTrigger,
  TabsContent,
  ToggleGroup,
  ToggleGroupItem,
  Table,
  TableBody,
  TableHead,
  TableRow,
  TableCell,
  Avatar,
  AvatarImage,
  AvatarFallback,
  Skeleton,
  EmptyState,
  useToast,
} from "@gunjo/ui";
import {
  IconCheck,
  IconShoppingCartPlus,
  IconBolt,
  IconTruck,
  IconShieldCheck,
  IconRefresh,
  IconHeart,
  IconPackageOff,
} from "@tabler/icons-react";
import { StarRating } from "./StarRating";
import { QuantityStepper } from "./QuantityStepper";
import {
  product,
  colors,
  sizes,
  galleryByColor,
  specifications,
  reviews,
  relatedProducts,
  formatJpy,
  discountPercent,
} from "./data";

export function ProductDetail() {
  const { showToast } = useToast();

  const [colorId, setColorId] = React.useState(colors[0].id);
  const [sizeId, setSizeId] = React.useState(
    sizes.find((s) => s.inStock)?.id ?? sizes[0].id,
  );
  const [qty, setQty] = React.useState(1);
  const [activeImageId, setActiveImageId] = React.useState(galleryByColor[colors[0].id][0].id);

  const gallery = galleryByColor[colorId];
  const activeImage = gallery.find((g) => g.id === activeImageId) ?? gallery[0];
  const selectedColor = colors.find((c) => c.id === colorId)!;
  const selectedSize = sizes.find((s) => s.id === sizeId)!;
  const variantInStock = selectedColor.inStock && selectedSize.inStock;

  // Keep the active image valid when the colour (and therefore gallery) changes.
  const handleColorChange = (next: string) => {
    if (!next) return; // ToggleGroup single can emit "" on deselect — ignore.
    setColorId(next);
    setActiveImageId(galleryByColor[next][0].id);
  };

  const handleSizeChange = (next: string) => {
    if (!next) return;
    setSizeId(next);
  };

  const addToCart = () => {
    showToast(
      `${product.name}（${selectedColor.name}・${selectedSize.label}）を${qty}点カートに追加しました`,
      "success",
    );
  };

  const buyNow = () => {
    showToast("安全な決済ページへ移動しています…", "info");
  };

  return (
    <div className="mx-auto w-full max-w-6xl px-4 pb-32 pt-6 sm:px-6 lg:pb-12">
      {/* Breadcrumb */}
      <Breadcrumb
        className="mb-6"
        items={[
          { label: "ホーム", href: "/" },
          { label: "オーディオ", href: "/product" },
          { label: "ヘッドホン", href: "/product" },
          { label: product.name },
        ]}
      />

      <div className="grid grid-cols-1 gap-8 lg:grid-cols-2 lg:gap-12">
        {/* ---------- Gallery ---------- */}
        <Gallery
          images={gallery}
          activeImage={activeImage}
          activeImageId={activeImage.id}
          onSelect={setActiveImageId}
          saleBadge={discountPercent > 0 ? `-${discountPercent}%` : null}
        />

        {/* ---------- Buy box ---------- */}
        <div className="flex flex-col gap-6">
          <header className="flex flex-col gap-3">
            <p className="text-sm font-medium uppercase tracking-wide text-muted-foreground">
              {product.brand}
            </p>
            <h1 className="text-2xl font-semibold leading-tight tracking-tight sm:text-3xl">
              {product.name}
            </h1>

            <div className="flex flex-wrap items-center gap-3">
              <StarRating value={product.rating} reviewCount={product.reviewCount} />
              <a href="#reviews" className="text-sm font-medium text-primary underline-offset-4 hover:underline">
                レビューを読む
              </a>
            </div>

            <div className="flex flex-wrap items-baseline gap-3 pt-1">
              <span className="text-3xl font-bold tracking-tight">{formatJpy(product.price)}</span>
              <span className="text-lg text-muted-foreground line-through" aria-label={`通常価格 ${formatJpy(product.compareAtPrice)}`}>
                {formatJpy(product.compareAtPrice)}
              </span>
              {discountPercent > 0 ? (
                <Badge variant="destructive">{discountPercent}%オフ</Badge>
              ) : null}
            </div>
            <p className="text-sm text-muted-foreground">価格は税込みです。送料は購入手続き時に計算されます。</p>
          </header>

          <p className="text-sm leading-relaxed text-foreground/90">{product.shortDescription}</p>

          <Separator />

          {/* Color swatches */}
          <fieldset className="flex flex-col gap-3">
            <legend className="flex w-full items-center justify-between text-sm font-medium">
              <span>
                カラー: <span className="text-muted-foreground">{selectedColor.name}</span>
              </span>
              {!selectedColor.inStock ? (
                <span className="text-xs font-normal text-destructive">在庫切れ</span>
              ) : null}
            </legend>
            <ToggleGroup
              type="single"
              value={colorId}
              onValueChange={handleColorChange}
              aria-label="カラーを選択"
              className="flex-wrap justify-start gap-2"
            >
              {colors.map((c) => (
                <ToggleGroupItem
                  key={c.id}
                  value={c.id}
                  disabled={!c.inStock}
                  aria-label={`${c.name}${c.inStock ? "" : "（在庫切れ）"}`}
                  className="relative h-10 w-10 rounded-full border border-border p-0 data-[state=on]:!bg-transparent data-[state=on]:ring-2 data-[state=on]:ring-foreground data-[state=on]:ring-offset-2 data-[state=on]:ring-offset-background"
                >
                  <span
                    className="block h-7 w-7 rounded-full"
                    style={{ backgroundColor: c.hex }}
                    aria-hidden="true"
                  />
                  {!c.inStock ? (
                    <span
                      aria-hidden="true"
                      className="pointer-events-none absolute inset-x-1 top-1/2 h-px -translate-y-1/2 rotate-45 bg-destructive"
                    />
                  ) : null}
                </ToggleGroupItem>
              ))}
            </ToggleGroup>
          </fieldset>

          {/* Size segmented control */}
          <fieldset className="flex flex-col gap-3">
            <legend className="flex w-full items-center justify-between text-sm font-medium">
              <span>
                サイズ: <span className="text-muted-foreground">{selectedSize.label}</span>
              </span>
              <a href="#specifications" className="text-xs font-normal text-primary underline-offset-4 hover:underline">
                サイズガイド
              </a>
            </legend>
            <ToggleGroup
              type="single"
              value={sizeId}
              onValueChange={handleSizeChange}
              variant="outline"
              aria-label="サイズを選択"
              className="flex-wrap justify-start gap-2"
            >
              {sizes.map((s) => (
                <ToggleGroupItem
                  key={s.id}
                  value={s.id}
                  disabled={!s.inStock}
                  aria-label={`${s.label}${s.inStock ? "" : "（在庫切れ）"}`}
                  className="px-4"
                >
                  {s.label}
                  {!s.inStock ? <span className="ml-1 text-xs">(在庫切れ)</span> : null}
                </ToggleGroupItem>
              ))}
            </ToggleGroup>
          </fieldset>

          <Separator />

          {/* Quantity + actions */}
          <div className="flex flex-col gap-4">
            <div className="flex items-center gap-4">
              <span id="qty-label" className="text-sm font-medium">
                数量
              </span>
              <QuantityStepper value={qty} onChange={setQty} min={1} max={10} label="数量" />
            </div>

            {variantInStock ? (
              <div className="flex flex-col gap-3 sm:flex-row">
                <Button
                  size="lg"
                  variant="primary"
                  className="w-full flex-1"
                  onClick={addToCart}
                >
                  <Icon icon={IconShoppingCartPlus} className="size-4" aria-hidden="true" />
                  カートに追加
                </Button>
                <Button
                  size="lg"
                  variant="outline"
                  className="w-full flex-1"
                  onClick={buyNow}
                >
                  <Icon icon={IconBolt} className="size-4" aria-hidden="true" />
                  今すぐ購入
                </Button>
                <Button
                  size="icon"
                  variant="outline"
                  className="h-10 w-10 shrink-0"
                  aria-label="お気に入りに追加"
                >
                  <Icon icon={IconHeart} className="size-4" aria-hidden="true" />
                </Button>
              </div>
            ) : (
              <EmptyState
                icon={<Icon icon={IconPackageOff} className="size-6 text-muted-foreground" aria-hidden="true" />}
                title="この組み合わせは在庫切れです"
                description="別のカラーやサイズをお選びいただくか、再入荷時にお知らせを受け取ってください。"
                headingLevel={2}
                action={
                  <Button
                    variant="outline"
                    onClick={() => showToast("再入荷した際にメールでお知らせします。", "info")}
                  >
                    再入荷をお知らせ
                  </Button>
                }
                className="border border-dashed"
              />
            )}
          </div>

          {/* Trust strip */}
          <ul className="grid grid-cols-1 gap-3 pt-2 text-sm text-muted-foreground sm:grid-cols-3">
            <li className="flex items-center gap-2">
              <Icon icon={IconTruck} className="size-4 text-foreground" aria-hidden="true" />
              送料無料・最短翌々日お届け
            </li>
            <li className="flex items-center gap-2">
              <Icon icon={IconRefresh} className="size-4 text-foreground" aria-hidden="true" />
              30日間返品可能
            </li>
            <li className="flex items-center gap-2">
              <Icon icon={IconShieldCheck} className="size-4 text-foreground" aria-hidden="true" />
              2年間保証
            </li>
          </ul>
        </div>
      </div>

      {/* ---------- Tabs ---------- */}
      <section className="mt-14" aria-label="商品詳細">
        <Tabs defaultValue="description" className="border-0">
          <TabsList className="w-full justify-start sm:w-auto">
            <TabsTrigger value="description">商品説明</TabsTrigger>
            <TabsTrigger value="specifications">仕様</TabsTrigger>
            <TabsTrigger value="reviews">レビュー（{product.reviewCount.toLocaleString()}）</TabsTrigger>
          </TabsList>

          <TabsContent value="description" className="px-0">
            <div className="max-w-3xl">
              <h2 className="text-lg font-semibold">音楽に溶けていく、自然なサウンド</h2>
              <p className="mt-2 text-sm leading-relaxed text-foreground/90">
                Aurora ANC は、ニュートラルで聴き疲れしないチューニングを施した
                40 mm バイオセルロースドライバーを中心に設計。ハイブリッド・アダプティブ
                ノイズキャンセリングが周囲の環境を1秒間に5万回読み取って静かに調整し、
                外音取り込みモードならワンタップで周りの音をそのまま取り込めます。
              </p>
              <ul className="mt-4 grid gap-2 sm:grid-cols-2">
                {product.highlights.map((h) => (
                  <li key={h} className="flex items-start gap-2 text-sm">
                    <Icon icon={IconCheck} className="mt-0.5 size-4 shrink-0 text-success" aria-hidden="true" />
                    <span>{h}</span>
                  </li>
                ))}
              </ul>
            </div>
          </TabsContent>

          <TabsContent value="specifications" id="specifications" className="px-0">
            <div className="max-w-3xl overflow-hidden rounded-lg border">
              <Table>
                <TableBody>
                  {specifications.map((spec) => (
                    <TableRow key={spec.label}>
                      <TableHead scope="row" className="w-1/3 align-top font-medium text-foreground">
                        {spec.label}
