interface GalleryProps {
  images: { id: string; src: string; alt: string }[];
  activeImage: { id: string; src: string; alt: string };
  activeImageId: string;
  onSelect: (id: string) => void;
  saleBadge: string | null;
}

function Gallery({ images, activeImage, activeImageId, onSelect, saleBadge }: GalleryProps) {
  const onThumbKeyDown = (e: React.KeyboardEvent, index: number) => {
    if (e.key === "ArrowRight" || e.key === "ArrowDown") {
      e.preventDefault();
      onSelect(images[(index + 1) % images.length].id);
    } else if (e.key === "ArrowLeft" || e.key === "ArrowUp") {
      e.preventDefault();
      onSelect(images[(index - 1 + images.length) % images.length].id);
    }
  };

  return (
    <div className="flex flex-col gap-4">
      <div className="relative">
        {saleBadge ? (
          <Badge variant="destructive" className="absolute left-3 top-3 z-10">
            {saleBadge}
          </Badge>
        ) : null}
        <Img
          key={activeImage.id}
          src={activeImage.src}
          alt={activeImage.alt}
          aspectRatio="square"
          className="border"
        />
      </div>

      {/* Thumbnails — a roving radiogroup-style strip */}
      <div role="radiogroup" aria-label="商品画像のサムネイル" className="grid grid-cols-4 gap-3">
        {images.map((img, i) => {
          const selected = img.id === activeImageId;
          return (
            <button
              key={img.id}
              type="button"
              role="radio"
              aria-checked={selected}
              aria-label={img.alt}
              tabIndex={selected ? 0 : -1}
              onClick={() => onSelect(img.id)}
              onKeyDown={(e) => onThumbKeyDown(e, i)}
              className={[
                "overflow-hidden rounded-lg border transition focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2",
                selected ? "border-foreground ring-1 ring-foreground" : "border-border hover:border-foreground/40",
              ].join(" ")}
            >
              <Img src={img.src} alt="" aspectRatio="square" showSkeleton={false} className="rounded-none border-0" />
            </button>
          );
        })}
      </div>
    </div>
  );
}

