"use client";

import * as React from "react";
import { Button, Icon } from "@gunjo/ui";
import { IconMinus, IconPlus } from "@tabler/icons-react";

/**
 * HAND-ROLLED horizontal − / value / + quantity stepper.
 *
 * @gunjo/ui ships `NumberInput`, but it's a vertical spinbox (stacked up/down
 * chevrons on the right edge), not the conventional commerce "− [n] +" control.
 * NumberInput also has no built-in visible affordance for a min/max boundary
 * other than disabling the tiny chevrons. So this is composed from gunjo
 * `Button` (size="icon") + `Icon`; the read-out is an aria-live spinbutton.
 */
export interface QuantityStepperProps {
  value: number;
  onChange: (value: number) => void;
  min?: number;
  max?: number;
  label?: string;
}

export function QuantityStepper({
  value,
  onChange,
  min = 1,
  max = 99,
  label = "数量",
}: QuantityStepperProps) {
  const clamp = (n: number) => Math.min(max, Math.max(min, n));
  const dec = () => onChange(clamp(value - 1));
  const inc = () => onChange(clamp(value + 1));

  const onKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === "ArrowUp" || e.key === "ArrowRight") {
      e.preventDefault();
      inc();
    } else if (e.key === "ArrowDown" || e.key === "ArrowLeft") {
      e.preventDefault();
      dec();
    } else if (e.key === "Home") {
      e.preventDefault();
      onChange(min);
    } else if (e.key === "End") {
      e.preventDefault();
      onChange(max);
    }
  };

  return (
    <div className="inline-flex items-center rounded-lg border border-input bg-transparent">
      <Button
        type="button"
        variant="ghost"
        size="icon"
        className="h-9 w-9 rounded-r-none"
        onClick={dec}
        disabled={value <= min}
        aria-label={`${label}を減らす`}
      >
        <Icon icon={IconMinus} className="size-4" aria-hidden="true" />
      </Button>
      <span
        role="spinbutton"
        tabIndex={0}
        aria-label={label}
        aria-valuenow={value}
        aria-valuemin={min}
        aria-valuemax={max}
        aria-live="polite"
        onKeyDown={onKeyDown}
        className="flex h-9 min-w-10 items-center justify-center px-2 text-sm font-medium tabular-nums outline-none focus-visible:ring-2 focus-visible:ring-ring"
      >
        {value}
      </span>
      <Button
        type="button"
        variant="ghost"
        size="icon"
        className="h-9 w-9 rounded-l-none"
        onClick={inc}
        disabled={value >= max}
        aria-label={`${label}を増やす`}
      >
        <Icon icon={IconPlus} className="size-4" aria-hidden="true" />
      </Button>
    </div>
  );
}

import * as React from "react";
import { Icon } from "@gunjo/ui";
import { IconStarFilled, IconStarHalfFilled, IconStar } from "@tabler/icons-react";

/**
 * HAND-ROLLED: @gunjo/ui ships no Rating / Stars component (verified: no match
 * for "rating"/"star" in the package's component sources). This is a core
 * e-commerce primitive, so it is reconstructed here from the Icon component +
 * Tabler glyphs. It is read-only (display) and exposes an accessible label.
 */
export interface StarRatingProps {
  /** Rating value, 0–5 (supports halves). */
  value: number;
  /** Max stars. Default 5. */
  max?: number;
  size?: "sm" | "md" | "lg";
  /** Optional review count to render next to the stars. */
  reviewCount?: number;
  className?: string;
}

const sizeMap = {
  sm: { star: "size-3.5", text: "text-xs" },
  md: { star: "size-4", text: "text-sm" },
  lg: { star: "size-5", text: "text-base" },
} as const;

export function StarRating({
  value,
  max = 5,
  size = "md",
  reviewCount,
  className,
}: StarRatingProps) {
  const sz = sizeMap[size];
  const rounded = Math.round(value * 2) / 2;
  const label =
    `5段階中${value}の評価` +
    (reviewCount !== undefined ? `、レビュー${reviewCount}件` : "");

  return (
    <span className={["inline-flex items-center gap-2", className].filter(Boolean).join(" ")}>
      <span role="img" aria-label={label} className="inline-flex items-center gap-0.5">
        {Array.from({ length: max }).map((_, i) => {
          const position = i + 1;
          const glyph =
            rounded >= position
              ? IconStarFilled
              : rounded >= position - 0.5
                ? IconStarHalfFilled
                : IconStar;
          return (
            <Icon
              key={i}
              icon={glyph}
              aria-hidden="true"
              className={`${sz.star} ${glyph === IconStar ? "text-muted-foreground/40" : "text-warning"}`}
            />
          );
        })}
      </span>
      {reviewCount !== undefined ? (
        <span className={`${sz.text} text-muted-foreground`} aria-hidden="true">
          {value.toFixed(1)} ({reviewCount.toLocaleString()})
        </span>
      ) : null}
    </span>
  );
}

"use client";

import * as React from "react";

/**
 * Bridges the OS `prefers-color-scheme` setting to @gunjo/ui's dark theme.
 *
 * FINDING: @gunjo/ui's dark mode is **class-based** (`.dark` selector in its
 * globals.css) with NO `@media (prefers-color-scheme: dark)` fallback and no
 * shipped ThemeProvider. So a consumer who wants "dark mode follows the system"
 * has to wire it themselves. This component is that glue: it toggles `.dark` on
 * <html> in response to the media query. (A first-class `ThemeProvider` /
 * `useTheme` in the design system would remove this boilerplate.)
 *
 * Scoped to the product route so it doesn't change the other demo pages.
 */
export function SystemThemeSync() {
  React.useEffect(() => {
    const mql = window.matchMedia("(prefers-color-scheme: dark)");
    const apply = (dark: boolean) => {
      document.documentElement.classList.toggle("dark", dark);
    };
    apply(mql.matches);
    const onChange = (e: MediaQueryListEvent) => apply(e.matches);
    mql.addEventListener("change", onChange);
    return () => {
      mql.removeEventListener("change", onChange);
      // leave the class as-is on unmount; other routes manage their own theme
    };
  }, []);

  return null;
}
